// Face Generator — subtle animation

let skinColors = {
  pale: [255, 224, 196],
  light: [241, 194, 125],
  medium: [224, 172, 105],
  tan: [198, 134, 66],
  brown: [141, 85, 36],
  dark: [101, 67, 33]
};

let hairColors = {
  black: [40, 40, 40],
  brown: [106, 78, 66],
  blonde: [255, 240, 165],
  red: [165, 42, 42],
  gray: [160, 160, 160],
  white: [250, 250, 250]
};

let eyeColors = {
  brown: [101, 67, 33],
  hazel: [150, 110, 80],
  green: [46, 139, 87],
  blue: [70, 130, 180],
  gray: [120, 120, 120],
  amber: [255, 191, 0]
};

p.setup = function() {
  p.createCanvas(400, 500);
  p.frameRate(30);
};

p.draw = function() {
  p.background(240, 240, 250);

  let headShape = 'oval';
  let skinTone = 'medium';
  let eyeColor = 'brown';
  let hairStyle = 'short';
  let hairColor = 'brown';
  let noseShape = 'straight';
  let mouthShape = 'full';

  headShape = p.getSynthVar('head_shape') || headShape;
  skinTone = p.getSynthVar('skin_tone') || skinTone;
  eyeColor = p.getSynthVar('eye_color') || eyeColor;
  hairStyle = p.getSynthVar('hair_style') || hairStyle;
  hairColor = p.getSynthVar('hair_color') || hairColor;
  noseShape = p.getSynthVar('nose_shape') || noseShape;
  mouthShape = p.getSynthVar('mouth_shape') || mouthShape;

  let t = p.frameCount;
  let breathY = p.sin(t * 0.018) * 2.5;
  let swayX = p.sin(t * 0.012) * 1.2;

  // Blink every ~4s (120 frames at 30fps), quick close/open
  let bc = t % 120;
  let blinkAmt = bc < 6 ? p.map(bc, 0, 6, 0, 1) :
                 bc < 12 ? p.map(bc, 6, 12, 1, 0) : 0;

  // Pupils follow mouse gently
  let eyeTrackX = p.map(p.mouseX, 0, p.width, -3, 3);
  let eyeTrackY = p.map(p.mouseY, 0, p.height, -2, 2);

  let skin = skinColors[skinTone] || [224, 172, 105];
  let hair = hairColors[hairColor] || [106, 78, 66];
  let eyes = eyeColors[eyeColor] || [101, 67, 33];

  p.push();
  p.translate(p.width / 2 + swayX, p.height / 2 + breathY);

  // Neck
  p.fill(skin[0], skin[1], skin[2]);
  p.noStroke();
  p.rect(-30, 100, 60, 100);

  // Head
  p.fill(skin[0], skin[1], skin[2]);
  p.stroke(0, 0, 0, 30);
  p.strokeWeight(2);

  if (headShape === 'oval') {
    p.ellipse(0, 0, 200, 250);
  } else if (headShape === 'round') {
    p.ellipse(0, 0, 220, 220);
  } else if (headShape === 'square') {
    p.rectMode(p.CENTER);
    p.rect(0, 0, 200, 220, 10);
    p.rectMode(p.CORNER);
  } else if (headShape === 'heart') {
    p.ellipse(0, -20, 200, 200);
    p.triangle(-80, 50, 80, 50, 0, 120);
  } else if (headShape === 'diamond') {
    p.quad(0, -120, 100, 0, 0, 120, -100, 0);
  } else {
    p.rectMode(p.CENTER);
    p.rect(0, 0, 180, 240, 10);
    p.rectMode(p.CORNER);
  }

  // Hair
  p.fill(hair[0], hair[1], hair[2]);
  p.noStroke();

  if (hairStyle !== 'bald') {
    let ls = p.sin(t * 0.022) * 5;
    if (hairStyle === 'short') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
    } else if (hairStyle === 'long') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
      p.beginShape();
      p.vertex(-30, -60);
      p.vertex(-105, -60);
      p.vertex(-108 + ls, 0);
      p.vertex(-104 + ls * 1.5, 60);
      p.vertex(-108 + ls * 2, 120);
      p.vertex(-30, 120);
      p.endShape(p.CLOSE);
      p.beginShape();
      p.vertex(30, -60);
      p.vertex(105, -60);
      p.vertex(108 - ls, 0);
      p.vertex(104 - ls * 1.5, 60);
      p.vertex(108 - ls * 2, 120);
      p.vertex(30, 120);
      p.endShape(p.CLOSE);
    } else if (hairStyle === 'wavy') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
      for (let i = 0; i < 5; i++) {
        let ws = p.sin(t * 0.025 + i * 0.9) * 6;
        p.ellipse(-80 + i * 40, 20 + ws, 30, 100);
      }
    } else if (hairStyle === 'curly') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
      for (let row = 0; row < 3; row++) {
        for (let col = 0; col < 5; col++) {
          let cs = p.sin(t * 0.022 + col * 1.1 + row * 0.7) * 3;
          p.circle(-80 + col * 40, -40 + row * 40 + cs, 35);
        }
      }
    } else {
      // straight
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
    }
  }

  // Eyes
  for (let side of [-1, 1]) {
    let ex = side * 40;
    let ey = -20;
    let px = p.constrain(ex + eyeTrackX, ex - 6, ex + 6);
    let py = p.constrain(ey + eyeTrackY, ey - 4, ey + 4);

    // White
    p.fill(255);
    p.noStroke();
    p.ellipse(ex, ey, 50, 35);

    // Iris
    p.fill(eyes[0], eyes[1], eyes[2]);
    p.circle(px, py, 25);

    // Pupil
    p.fill(0);
    p.circle(px, py, 12);

    // Specular highlight
    p.fill(255);
    p.circle(px + 4, py - 4, 5);

    // Blink eyelid descends from top
    if (blinkAmt > 0) {
      p.fill(skin[0], skin[1], skin[2]);
      p.noStroke();
      p.rect(ex - 27, ey - 18, 54, 37 * blinkAmt, 3);
    }
  }

  // Eyebrows
  p.stroke(Math.max(0, hair[0] - 30), Math.max(0, hair[1] - 30), Math.max(0, hair[2] - 30));
  p.strokeWeight(4);
  p.noFill();
  p.arc(-40, -45, 50, 20, p.PI, p.TWO_PI);
  p.arc(40, -45, 50, 20, p.PI, p.TWO_PI);

  // Nose — all shapes get proper nostrils
  p.noStroke();
  p.fill(Math.max(0, skin[0] - 15), Math.max(0, skin[1] - 15), Math.max(0, skin[2] - 15));

  if (noseShape === 'button') {
    p.ellipse(0, 18, 26, 18);
    p.fill(Math.max(0, skin[0] - 28), Math.max(0, skin[1] - 28), Math.max(0, skin[2] - 28));
    p.ellipse(-8, 23, 11, 8);
    p.ellipse(8, 23, 11, 8);
  } else if (noseShape === 'long') {
    p.ellipse(0, 28, 18, 50);
    p.fill(Math.max(0, skin[0] - 28), Math.max(0, skin[1] - 28), Math.max(0, skin[2] - 28));
    p.ellipse(-7, 42, 10, 8);
    p.ellipse(7, 42, 10, 8);
  } else if (noseShape === 'broad') {
    p.ellipse(0, 20, 42, 28);
    p.fill(Math.max(0, skin[0] - 28), Math.max(0, skin[1] - 28), Math.max(0, skin[2] - 28));
    p.ellipse(-14, 24, 13, 9);
    p.ellipse(14, 24, 13, 9);
  } else if (noseShape === 'upturned') {
    p.ellipse(0, 14, 22, 16);
    p.fill(Math.max(0, skin[0] - 28), Math.max(0, skin[1] - 28), Math.max(0, skin[2] - 28));
    p.ellipse(-8, 16, 11, 10);
    p.ellipse(8, 16, 11, 10);
  } else if (noseShape === 'narrow') {
    p.ellipse(0, 20, 14, 36);
    p.fill(Math.max(0, skin[0] - 28), Math.max(0, skin[1] - 28), Math.max(0, skin[2] - 28));
    p.ellipse(-5, 30, 8, 7);
    p.ellipse(5, 30, 8, 7);
  } else {
    // straight
    p.ellipse(0, 20, 18, 32);
    p.fill(Math.max(0, skin[0] - 28), Math.max(0, skin[1] - 28), Math.max(0, skin[2] - 28));
    p.ellipse(-7, 28, 9, 8);
    p.ellipse(7, 28, 9, 8);
  }

  // Mouth — two-lip style with seam line
  p.noStroke();
  if (mouthShape === 'heart') {
    p.fill(190, 80, 80);
    p.arc(-14, 73, 30, 22, 0, p.PI);
    p.arc(14, 73, 30, 22, 0, p.PI);
    p.fill(215, 105, 105);
    p.arc(-14, 68, 30, 16, p.PI, p.TWO_PI);
    p.arc(14, 68, 30, 16, p.PI, p.TWO_PI);
  } else {
    let lipW = 60, lipH = 20;
    if (mouthShape === 'thin') { lipW = 50; lipH = 12; }
    else if (mouthShape === 'wide') { lipW = 80; lipH = 20; }
    else if (mouthShape === 'small') { lipW = 32; lipH = 14; }
    else if (mouthShape === 'curved') { lipW = 58; lipH = 18; }
    p.fill(190, 80, 80);
    p.arc(0, 73, lipW, lipH + 5, 0, p.PI);
    p.fill(215, 105, 105);
    p.arc(0, 68, lipW, lipH, p.PI, p.TWO_PI);
    p.stroke(160, 55, 55);
    p.strokeWeight(1.5);
    p.noFill();
    p.line(-lipW / 2, 70, lipW / 2, 70);
    p.noStroke();
  }

  p.pop();
};
